def _links(name: str, brand: str) -> dict:
    q = f"{brand} {name}".replace(" ", "+")
    return {
        "amazon":   f"https://www.amazon.in/s?k={q}",
        "nykaa":    f"https://www.nykaa.com/search/result/?q={q}",
        "flipkart": f"https://www.flipkart.com/search?q={q}",
    }


